$msbuild = "C:\Program Files\Microsoft Visual Studio\18\Community\MSBuild\Current\Bin\MSBuild.exe"
$project1 = "C:\Users\Administrator\Desktop\DSC CHINA NX4\NX4C REAR\RH_JA02\RH_JA02(202).vbproj"
$project2 = "C:\Users\Administrator\Desktop\DSC CHINA NX4\NX4C REAR\LH_JA02\LH_JA02(212).vbproj"
$exeDir = "C:\Users\Administrator\Desktop\DSC CHINA NX4\exe"

Write-Host "=== Building RH_JA02 ===" -ForegroundColor Yellow
& $msbuild $project1 /p:Configuration=Release /p:Platform="Any CPU"
$rh_result = $LASTEXITCODE
Write-Host "RH_JA02 build exit code: $rh_result" -ForegroundColor Cyan

Write-Host "`n=== Building LH_JA02 ===" -ForegroundColor Yellow
& $msbuild $project2 /p:Configuration=Release /p:Platform="Any CPU"
$lh_result = $LASTEXITCODE
Write-Host "LH_JA02 build exit code: $lh_result" -ForegroundColor Cyan

if ($rh_result -eq 0 -and $lh_result -eq 0) {
    Write-Host "`n=== Build Successful ===" -ForegroundColor Green

    # Find output files
    $rh_out = Get-ChildItem -Path "C:\Users\Administrator\Desktop\DSC CHINA NX4\NX4C REAR\RH_JA02" -Filter "*.exe" -Recurse | Where-Object { $_.Name -like "*20260313*" } | Select-Object -First 1
    $lh_out = Get-ChildItem -Path "C:\Users\Administrator\Desktop\DSC CHINA NX4\NX4C REAR\LH_JA02" -Filter "*.exe" -Recurse | Where-Object { $_.Name -like "*20260313*" } | Select-Object -First 1

    if ($rh_out) {
        Write-Host "RH_JA02 output: $($rh_out.FullName)"
    } else {
        Write-Host "WARNING: RH_JA02 exe not found with 20260313 in name" -ForegroundColor Red
    }

    if ($lh_out) {
        Write-Host "LH_JA02 output: $($lh_out.FullName)"
    } else {
        Write-Host "WARNING: LH_JA02 exe not found with 20260313 in name" -ForegroundColor Red
    }

    # Remove old files
    Write-Host "`n=== Removing old files ===" -ForegroundColor Yellow
    if (Test-Path "$exeDir\REAR RH_JA02(20260313).exe") {
        Remove-Item "$exeDir\REAR RH_JA02(20260313).exe" -Force
        Write-Host "Deleted: REAR RH_JA02(20260313).exe"
    }

    if (Test-Path "$exeDir\REAR LH_JA02(20260313).exe") {
        Remove-Item "$exeDir\REAR LH_JA02(20260313).exe" -Force
        Write-Host "Deleted: REAR LH_JA02(20260313).exe"
    }

    # Copy new files
    Write-Host "`n=== Copying new files ===" -ForegroundColor Yellow
    if ($rh_out) {
        Copy-Item $rh_out.FullName "$exeDir\$($rh_out.Name)" -Force
        Write-Host "Copied: $($rh_out.Name)"
    }

    if ($lh_out) {
        Copy-Item $lh_out.FullName "$exeDir\$($lh_out.Name)" -Force
        Write-Host "Copied: $($lh_out.Name)"
    }

    Write-Host "`n=== Exe folder contents ===" -ForegroundColor Cyan
    Get-ChildItem $exeDir -Filter "*20260313*" | Select-Object Name, LastWriteTime
} else {
    Write-Host "`n=== Build Failed ===" -ForegroundColor Red
}
